final:
module RefModule(
	input clk,
	input rst_n,
	output sink_sop,
	output sink_eop
);reg [10:0] obf_counter;

always@(posedge clk)
if(!rst_n)
	obf_counter<=11'd0;
else if(obf_counter>=11'd1030)
	obf_counter<=11'd0;
else
	obf_counter<=obf_counter+1'b1;


assign sink_sop=(obf_counter==11'd0)?1'b1:1'b0;

assign sink_eop=(obf_counter==11'd1023)?1'b1:1'b0;

endmodule
